{
  "name": "smartresponsor/attachment",
  "description": "Symfony-oriented attachment component for Smart Responsor",
  "type": "project",
  "license": "proprietary",
  "require": {
  "php": "^8.4",
  "ext-fileinfo": "*",
  "doctrine/dbal": "^4.2",
  "doctrine/orm": "^3.3",
  "doctrine/doctrine-bundle": "^3.1",
  "symfony/config": "^8.0",
  "symfony/console": "^8.0",
  "symfony/dependency-injection": "^8.0",
  "symfony/filesystem": "^8.0",
  "symfony/form": "^8.0",
  "symfony/framework-bundle": "^8.0",
  "symfony/http-foundation": "^8.0",
  "symfony/http-kernel": "^8.0",
  "symfony/mime": "^8.0",
  "symfony/routing": "^8.0",
  "symfony/security-bundle": "^8.0",
  "symfony/serializer": "^8.0",
  "symfony/validator": "^8.0",
  "symfony/yaml": "^8.0"
},
"require-dev": {
  "doctrine/doctrine-fixtures-bundle": "^4.0",
  "fakerphp/faker": "^1.24",
  "friendsofphp/php-cs-fixer": "^3.75",
  "phpstan/phpstan": "^2.1",
  "phpunit/phpunit": "^12.1",
  "symfony/browser-kit": "^8.0",
  "symfony/css-selector": "^8.0"
},
  "autoload": {
    "psr-4": {
      "App\\": "src/"
    }
  },
  "autoload-dev": {
    "psr-4": {
      "App\\Tests\\": "tests/"
    }
  },
  "scripts": {
    "cs:check": "php-cs-fixer fix --dry-run --diff --verbose",
    "cs:fix": "php-cs-fixer fix --verbose",
    "phpstan": "phpstan analyse",
    "test": "phpunit"
  }
}
